#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        if(N==0){
            printf("0\n");
        }else if(N % K == 0){
            printf("%lld\n", N / K);
        }else{
            printf("-1\n");
        }
    }
    return 0;
}

